const Q_ECONOMICS_2000=[{"id": "objective>Economics>2000>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economics can be defined as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reduction in spending in the face of competing alternatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allocation of resources to alternative uses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic behaviour of small units like the household and the firm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the study of economic aggregates like inflation and national income </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economics is a social science that studies how individuals, governments, firms, and nations make choices on allocating resources to satisfy their unlimited wants. Therefore, the definition that best fits is 'allocation of resources to alternative uses'. This involves making decisions about the distribution of resources among different potential uses, which is a fundamental problem in economics.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2000>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>I</strong> What and how much will be produced?  <br/>  <strong>II</strong> How will it be produced?  <br/>   <strong>III</strong> For whom will it be produced? <br/>  <strong>IV</strong> How much will be exported and consumed?  <br/>  From the above, identify the combination of basic resource allocation questions in economic analysts</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II, III and IV</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III.the basic problems of every society are what to produced,how to produced,for whom to produced and efficient uses of resources </div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2000>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> How many students took the examination?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">280</div>", "<div style=\"font-family:Cambria;font-size:17px;\">240</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">0 - 19 = 40 <br/>  20 - 39 = 80  <br/>  40 - 59 = 100  <br/>  60 - 69 = 40 <br/>  70 - 100 = 20</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total students = 280</td></tr></table></div>.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2000>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> If the pass mark was 40, how many students passed the examination?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120</div>", "<div style=\"font-family:Cambria;font-size:17px;\">160</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Scores</td><td style=\"border:1px solid black;text-align:center;\">Number of students</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">40 - 59 <br/> 60 - 69 <br/> 70 - 100</td><td style=\"border:1px solid black;text-align:center;\">100 <br/> 40 <br/> 20</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Total</td><td style=\"border:1px solid black;text-align:center;\">160 students</td></tr></table></div>.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2000>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a capitalist economy, the economic problem of what goods to produce is decided mainly by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shadow prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a central planner </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Relative prices are the prices of goods and services relative to each other. They reflect the scarcity of goods and services and the demand for them. <br/>  <br/> In a capitalist economy, businesses are motivated to produce goods and services that consumers are willing to pay for. This means that businesses will produce goods and services that have high relative prices. <br/>  <br/> The other options are not as important in determining what goods to produce in a capitalist economy. <br/> -  Shadow prices: Shadow prices are hypothetical prices that are used to evaluate the efficiency of government projects. They are not used to determine what goods to produce in a capitalist economy. <br/> -  Profit level: Profit level is important for businesses, but it is not the only factor that businesses consider when deciding what goods to produce. Businesses also consider the relative prices of goods and services and the demand for goods and services. <br/> -  Central planner: Central planners are not used in capitalist economies. In a capitalist economy, businesses are free to produce whatever goods and services they want.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}, {"id": "objective>Economics>2000>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an example of derived demand?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Tax relief</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wage increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Entertainment</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A derived demand is a demand for a commodity, service, etc. which is a consequence of the demand for something else. Labour is a derived demand.it is the demand for a commodity not for immediate consumption but for what it can help to produced.</div>", "topic": "THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2000>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the information below to answer this question. <br/>  When commodity <strong>X</strong> sold for ₦25 per unit, 50 units of commodity <strong>Y</strong> were purchased. With an increase in the price of commodity <strong>X</strong> to ₦50 per unit, the demand for commodity <strong>Y</strong> fell to 20 units. <br/>  <br/> Determine the cross elasticity of demand </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-0.6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1.7</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%Δ in Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span><hr size=\"1\" />%Δ in P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">X</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Cross</td><td style=\"text-align:center;\">Elasticity</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">demand</td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%Δ</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20 - 50<hr size=\"1\" />50</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-30<hr size=\"1\" />50</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-60</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">%Δ</td><td style=\"text-align:center;\">in</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">X</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">50 - 25<hr size=\"1\" />25</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>   <br/>   <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">25<hr size=\"1\" />25</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div> = 100%  <br/>   <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ED</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">% Δ in Quantity Y<hr size=\"1\" />% Δ in Price Y</td></tr></table></div>   = -60/100 = -0.6.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2000>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the information below to answer this question. <br/>  When commodity <strong>X</strong> sold for ₦25 per unit, 50 units of commodity <strong>Y</strong> were purchased. With an increase in the price of commodity <strong>X</strong> to ₦50 per unit, the demand for commodity <strong>Y</strong> fell to 20 units. <br/> The two commodities can be classified as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">durable and non-durable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intermediate and final </div>", "<div style=\"font-family:Cambria;font-size:17px;\">complements</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The goods are complementary goods i.e an increase in price of one good result to decrease in demand for the other. </div>", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>2000>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A central argument of cardinal utility is that utility is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">measurable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">psychological</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ranked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intangible</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cardinal utility is a view of utility measurement based on the presumption that the satisfaction of wants and needs is a quantifiable characteristic of human activity. In other words, utility can be measured with numerical values (1, 2, 3, etc.) along a scale.the unit of utility according to the cardinalist is utils.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : UTILITY SCHOOL OF THOUGHT"}, {"id": "objective>Economics>2000>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The age distribution of a country's population determines the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ratio of the dependent to the working group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total age of all working class adults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">male-female ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">percentage of married women</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The dependency ratio is the number of dependents in a population divided by the number of working age people. Dependents are defined as those aged zero to 14 and those aged 65 and older. Working age is from 15 to 64. The ratio describes how much pressure an economy faces in supporting its non-productive population.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2000>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Commodities I and II are in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">competitive supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">joint supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">substitute supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived supply</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Joint supply implies goods and services produced from one source. It can be seen from the graph that as commodity I increases in demand, it resulted in increase in supply of commodity II which explains joint supply.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2000>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The supply of commodity II increasing from S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> to S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leads to a fall in price from OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> to OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">moves the price below OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases the price from OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> to OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">moves the price to OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In commodity II,  demand is held constant, and the supply shift from S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> to S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>( increase) which lead to a fall in price from OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> to OP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2000>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a free market system, trading can only take place when the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">market is not working efficiently </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equilibrium price is attained</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price of a commodity tends to attract consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer sovereignty is lacking</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A free market economy, the price of a commodities are determined by the forces of demand and supply or price system (Mechanism) i.e the price is determined where demand equates supply.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2000>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The condition for equilibrium price and quantity under perfect competition is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MC = AR = TR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TC = AR = P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC = AR = P</div>", "<div style=\"font-family:Cambria;font-size:17px;\">MC = AR = TC</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a perfect competitive market, the MR is also the AR , Price (P). Therefore, the equilibrium is achieved when the MC = MR = AR = P.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2000>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">External diseconomics of scale result from excessive growth of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the whole industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">some sectors of the industry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">external factors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">internal factors</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">External diseconomies of scale occur when the cost per unit of output increases with the size of the industry, not the firm. This happens when the industry's expansion leads to an increase in the costs of production and inefficiencies. Therefore, external diseconomies of scale result from excessive growth of the whole industry.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2000>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the table below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The marginal product <strong>X</strong> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24</div>", "<div style=\"font-family:Cambria;font-size:17px;\">25</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">MP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">X</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">ΔTP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span><hr size=\"1\" />ΔQ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">X</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">48 - 24<hr size=\"1\" />4 - 3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">24<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">24</td><td style=\"text-align:center;\"></td></tr></table></div></div>", "topic": "THEORY OF PRODUCTION (1) : FACTORS OF PRODUCTION"}, {"id": "objective>Economics>2000>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the table below to answer this question  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The average product <strong>Y</strong> is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.5</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The average product <strong>Y</strong> is  <br/>  <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">AP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">TP<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span><hr size=\"1\" />Q<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Y</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">93<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">15.5</td><td style=\"text-align:center;\"></td></tr></table></div></div>", "topic": "THEORY OF PRODUCTION (1) : FACTORS OF PRODUCTION"}, {"id": "objective>Economics>2000>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a small scale business, the fixed cost is ₦5,000.00, variable cost is ₦15,000.00 and the output is 500units. What will be the unit cost of the goods?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦40.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦80.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦60.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20.00</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The unit cost of goods is calculated by adding the fixed cost and variable cost and then dividing by the number of units. In this case, the fixed cost is ₦5,000.00 and the variable cost is ₦15,000.00, making the total cost ₦20,000.00. This total cost is then divided by the number of units, which is 500, to get the unit cost. Therefore, the unit cost is ₦20,000.00 / 500 = ₦40.00.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2000>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a total cost curve is plotted, marginal cost can be illustrated by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">slope of the tangent to the curve at any given output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">U-shaped curve cutting the total cost curve at its lowest point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">straight line from the origin to the mid-point of the curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">straight line cutting the curve at its highest point</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal cost is the cost of producing one more unit of a good. In a graph, it is represented by the slope of the tangent to the total cost curve at any given output.</div>", "topic": "THE CONCEPT OF COST & REVENUE : THE MARGINAL COST & SUPPLY CURVE OF A FIRM"}, {"id": "objective>Economics>2000>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In a price-taking firm, the portion UT above is the firm's </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average revenue curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">supply curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">demand curve</div>", "<div style=\"font-family:Cambria;font-size:17px;\">long-run average cost curve</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">UT represents supply curve since the curve is positively sloped.The marginal cost curve represent the supply curve of a firm.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2000>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run equilibrium in a perfectly competitive market requires that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">marginal cost be equal to total revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal cost and marginal revenue be equal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">costs are mutually determined by buyers and sellers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the marginal cost curve cuts the total cost curve</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short run, marginal cost and marginal revenue must be equal i. e MC = MR also the MC must cuts the MR from below.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2000>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The firm whose sales and total revenue of the commodity as given above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a monopolist </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a monopolistic competitor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a perfect competitor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an oligopolist</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A monopolist makes maximum profit from the sale of its product both in the short run and long run. Hence, As quantity increases, his revenue also increases.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2000>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At the point where marginal revenue of a monopolist is equal to zero, its total revenue will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">falling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rising</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the point where marginal revenue of a monopolist is equal to zero, its total revenue will be at its maximum. This is because marginal revenue is the additional revenue that a firm receives from selling one more unit of a good. When marginal revenue is zero, it means that selling one more unit of the good will not increase total revenue, implying that total revenue has reached its maximum.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2000>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A distinguishing characteristic of cooperative societies is that voting power depends on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">number of shares held</div>", "<div style=\"font-family:Cambria;font-size:17px;\">status of the member</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equality of members</div>", "<div style=\"font-family:Cambria;font-size:17px;\">management's decision</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Each member of the society has equal say in the organisation. Members are entitled to one-man-one vote right, irrespective of shares hold.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>2000>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept of privatization presupposes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">efficiency</div>", "<div style=\"font-family:Cambria;font-size:17px;\">market price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">indigenization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign trade</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Privatization is the process of transferring ownership of a business, enterprise, agency, public service, or public property from the public sector (a government) to the private sector, either to a business that operates for a profit or to a nonprofit organization. The underlying premise of privatization is to increase efficiency, as private companies, driven by profit motive, are generally believed to operate more efficiently than government entities.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : COMMERCIALISATION & PRIVATISATION"}, {"id": "objective>Economics>2000>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One problem in the marketing of agricultural products in Nigeria is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the seasonal nature of the commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high price of the commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the changing tastes of consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate storage facilities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lots of products are wasted due to lack of storage and processing facilities. The farmers do not have the technical know-how to operate these storage and processing facilities, which are very expensive to purchase and maintain.</div>", "topic": "AGRICULTURE IN WEST AFRICA : MARKETING BOARDS"}, {"id": "objective>Economics>2000>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Increased output will cause farmer's revenue to decrease when market demand is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inelastic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unitary elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly elastic </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The effects on the revenues received by farmers from the sale of their crops depends on the elasticity. However, Farm revenue and output will vary in the opposite directions whenever demand for the product is inelastic and will vary in the same direction whenever demand for the product is elastic. <br/>  <br/> Therefore, from the question above, option B is correct because the revenue and output varies in opposite direction.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2000>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A primary industry is concerned with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">extraction of resources in their raw state </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the operation of small scale enterprises</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the economic activities of primary producers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">clearing and cultivation of land only</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The primary sector of the economy is the sector which deals with the extraction of natural resources or raw material. This includes agriculture, forestry, fishing and mining.</div>", "topic": "THEORY OF PRODUCTION (1) : INTRODUCTION"}, {"id": "objective>Economics>2000>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The slow pace of industrial growth in Nigeria can be attributed to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">overdependence on the oil sector</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate number of unskilled labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lack of raw materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate infrastructural facilities</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The slow pace of industrial growth in Nigeria can be attributed to inadequate infrastructural facilities. Infrastructure is a key component of industrial development. This includes things like roads, power, water, and telecommunications. Without these facilities, industries cannot operate efficiently. Overdependence on the oil sector, lack of raw materials, and inadequate number of unskilled labour are also factors, but they are not the primary cause.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2000>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Industries contribute to national economic development because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">utilize local raw materials </div>", "<div style=\"font-family:Cambria;font-size:17px;\">employ an increasing number of labour</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide recreational facilities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">use modern machines which replace human labour </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industries contribute to national economic development because they utilize local raw materials. This is because industries, by using local raw materials, add value to these materials, create jobs, and contribute to the GDP of the nation. This process of adding value to raw materials is known as industrialization, which is a key driver of economic development.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INDIGENISATION & NATIONALISATION"}, {"id": "objective>Economics>2000>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian economy is monocultural because government revenue is derived mainly from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">agriculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crude oil</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigerian economy is considered monocultural because its government revenue is derived mainly from crude oil. A monocultural economy is an economic system that relies on one commodity for a large part of its exports and revenue. In the case of Nigeria, crude oil accounts for about 90% of its export earnings and more than half of the government's revenue.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2000>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As a producers' association, the OPEC expects its members to maintain production where marginal cost is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to price</div>", "<div style=\"font-family:Cambria;font-size:17px;\">equal to average cost </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, the optimal point of production is where marginal cost equals price. This is because at this point, the cost of producing an additional unit of output equals the revenue gained from selling that unit, thus maximizing profit. Therefore, OPEC, as a producers' association, would expect its members to maintain production where marginal cost is equal to price.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>2000>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A well conducted census is important for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">effective defense</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effective revenue generation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">good economic planning</div>", "<div style=\"font-family:Cambria;font-size:17px;\">optimum population</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Census is conducted to know the number of males and females in a country and also to determine the number of unemployed citizens in a country. However, One of the essential features of census is good economic plans.</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>2000>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The age distribution of a country's population determines the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ratio of the dependent to the working group</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total age of all working class adults</div>", "<div style=\"font-family:Cambria;font-size:17px;\">male-female ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">percentage of married women</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Age distribution, also called Age Composition, in population studies determines the proportionate numbers of persons in successive age categories in a given population</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2000>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Firms continue to employ workers until the wage rate equals the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average product of labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marginal revenue product of labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total product of labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sum of marginal revenue and average revenue of labour</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the Marginal Productivity Theory of Wages, wages in a  competitve market tend to be equal to the marginal product of labour i.e W = MPL since the Marginal revenue product  = MPP  x P.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : DEMAND FOR LABOUR"}, {"id": "objective>Economics>2000>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, if W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> are different wage rates, the minimum wage rate is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum wage rate that is fixed above the equilibrum wage rate. In the diagram, W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is the minimum wage paid to employees/ labour. </div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : INTRODUCTION"}, {"id": "objective>Economics>2000>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major effect of a long distribution chain is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high retail prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity of commodities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low retail prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low producer earnings </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It will lead to high retail prices as each of the merchants along the distribution line will have a profit margin.since each seller want to make profit they inflate the price.</div>", "topic": "DISTRIBUTIVE TRADE : THE RETAILER"}, {"id": "objective>Economics>2000>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major function of the wholesaler to his customers is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">breaking of bulk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">offering personal services </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stocking a variety of goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">providing transport facilities</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major function of a wholesaler is to buy large quantities of goods from producers and break them down into smaller quantities for resale to retailers. This process is known as 'breaking of bulk'. Therefore, the correct answer is 'breaking of bulk'.</div>", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER"}, {"id": "objective>Economics>2000>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is used for measuring national income ?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Output, income and wages </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Import, expenditure and output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Income, output and expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Export, Import and Output</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">National income is the total value of all services and goods produced within a country and the income received from abroad. It is usually measured using three methods: the income method, the output or production method, and the expenditure method. The income method sums up all the incomes earned by the factors of production, i.e., rent (for land), wages (for labor), interest (for capital), and profits (for entrepreneurship). The output method sums up the market value of all final goods and services produced in an economy in a given period. The expenditure method sums up all the spending to buy things. It includes consumption, investment, government spending, and net exports (exports minus imports). Therefore, the correct answer is 'Income, output and expenditure'.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2000>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Exclusions that make Gross National Product a poor measure of welfare are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">government purchases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government military outlays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wages and salaries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">housewives' services</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The limitation of GNP are: <br/> -    Women's share in national income, <br/>  <br/> -   Impact of urbanization on various aspects of national income aggregates, <br/>  <br/> -   Technological changes and their measurement in the economy, <br/>  <br/> -   Proposals for a revised series of national state income, capital formation and savings, <br/>  <br/> -   Recent developments in the estimation of state domestic product, <br/>  <br/> -   Capital loss and its possible treatment in national income accounts, <br/>  <br/> -  The problem of output and its valuation in household sectors etc.</div>", "topic": "NATIONAL INCOME : PROBLEMS OF NATIONAL INCOME"}, {"id": "objective>Economics>2000>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in money supply, other things being equal will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lower interest rates</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ensure trade balance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase money demand</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The term money supply is used to explain the total amount of money available in the economy to the public. Due to the increase in the money supply, keeping other things remain constant. The investment spending rise and due to the increase of money, the real interest rate will fall so that it will not become expensive for the customer to take out the loan.   <br/>  <br/> Hence, it shows a direct relationship between the change in money supply and the investment spending while in respect of real interest rate it shows an inverse relationship between the change in money supply and real interest rate.  </div>", "topic": "MONEY : SUPPLY OF MONEY"}, {"id": "objective>Economics>2000>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A persistent rise in the general level of prices implies</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in some places </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a one-time rise in prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a steady fall in the purchasing power of money</div>", "<div style=\"font-family:Cambria;font-size:17px;\">that the higher the price level, the more the value of money </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A persistent rise in the general level of prices implies a steady fall in the purchasing power of money. This is because as prices increase, the same amount of money can buy fewer goods and services. This is the concept of inflation, where the value of money decreases as the general level of prices increases.</div>", "topic": "INFLATION & DEFLATION : EFFECT"}, {"id": "objective>Economics>2000>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two principal ways by which banks can lend money to their customers are through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loans and overdrafts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loans and discounting bills</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overdrafts and cheques</div>", "<div style=\"font-family:Cambria;font-size:17px;\">overdrafts and treasury bills</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">loans and overdrafts: An overdraft occurs when money is withdrawn from a bank account and the available balance goes below zero. In this situation the account is said to be \"overdrawn\" and it can be given a customer who have a current account.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2000>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A capital market differs from the money market in that in the former</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">loan sought is short term </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loan repayment is guaranteed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loan sought is long term</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the percentage of interest charged is more</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capital market seeks to provide long term financing. It is a market where buyers and sellers engage in trade of financial securities like bonds, stocks, etc.</div>", "topic": "FINANCIAL INSTITUTION : INTRODUCTION"}, {"id": "objective>Economics>2000>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An aspect of taxation that involves normative economics is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tax rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">effect on incentive to work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairness of the tax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tax burden</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Normative economics (as opposed to positive economics) is a part of economics whose objective is fairness or what the outcome of the economy or goals of public policy ought to be.  <br/> Tax fairness is a concept which stipulates that a government's tax system should be equitable to all citizens</div>", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION"}, {"id": "objective>Economics>2000>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Public debt is composed of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">internal debts and World Bank loans</div>", "<div style=\"font-family:Cambria;font-size:17px;\">money owed to local and foreign contractors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">internal and external debts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">loans granted by IMF and ADB</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Government debt; also known as public debt, national debt and sovereign debt is the debt owed by a central government. It is composed of internal and external debts.</div>", "topic": "PUBLIC FINANCE : INTRODUCTION"}, {"id": "objective>Economics>2000>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country exporting mainly primary products and with a high percentage of her labour force in agriculture is said to be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">developing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">developed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor</div>", "<div style=\"font-family:Cambria;font-size:17px;\">underdeveloped</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A country that exports mainly primary products and has a high percentage of its labor force in agriculture is typically referred to as a developing country. This is because developed countries usually have a more diverse range of exports and a smaller percentage of their labor force in agriculture, as they have moved towards more industrial and service-based economies.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2000>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A country's import price index by 1995 was 50 and her index of export price was 70. Calculate the terms of trade</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">20%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">71%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">140%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T.O.T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Index of export price<hr size=\"1\" />Index of import rice</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">100<hr size=\"1\" />1</td></tr></table></div>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">70<hr size=\"1\" />50</td><td style=\"text-align:center;\">x</td><td style=\"text-align:center;\">100</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">140%</td><td style=\"text-align:center;\"></td></tr></table></div></div>", "topic": "INTERNATIONAL TRADE : TERMS OF TRADE"}, {"id": "objective>Economics>2000>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the United Kingdom buys gold for ∈ 60 an ounce and Nigeria buys the same ounce for ₦500. What will be United Kingdom's exchange rate with Nigeria?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">∈ 0.05 = ₦1.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">∈ 0.06 = ₦1.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">∈ 0.11 = ₦1.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">∈ 0.12 = ₦1.00</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">United Kingdom's exchange rate with Nigeria <br/> ∈60 = ₦500  <br/>  <br/>  <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">60<hr size=\"1\" />500</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">∈0.12</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">₦1.00</td><td style=\"text-align:center;\"></td></tr></table></div></div>", "topic": "INTERNATIONAL TRADE : EXCHANGE RATE"}, {"id": "objective>Economics>2000>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Being a member of the OPEC, Nigeria is in a favourable position to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">export her crude oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">control world crude oil prices</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reap the benefit of a cartel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">borrow money from members</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria can reap the benefit of a cartel.OPEC is a cartel and the OPEC Member Countries adjust their oil productions activities in order to bring stability to the petroleum market and help manufacturers get a good return on their investments. This policy is also designed to ensure that oil consumers continue to receive stable supplies of oil.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : OPEC"}];
